@dataclass
class JobMessage:
    message_id: str
    receipt_handle: str
    message_type: str
    payload: Dict[str, Any]
    attributes: Dict[str, Any] = field(default_factory=dict)
    timestamp: datetime = field(default_factory=datetime.utcnow)
    retry_count: int = 0

    @classmethod
    def from_sqs_message(cls, sqs_message: Dict) -> 'JobMessage':
        body = json.loads(sqs_message['Body'])
        attributes = sqs_message.get('MessageAttributes', {})
        retry_count = int(
            attributes.get('RetryCount', {}).get('StringValue', '0')
        )
        return cls(
            message_id=sqs_message['MessageId'],
            receipt_handle=sqs_message['ReceiptHandle'],
            message_type=body.get('type', 'unknown'),
            payload=body.get('payload', {}),
            attributes=body.get('attributes', {}),
            retry_count=retry_count,
        )


