class HandlerRegistry:
    def __init__(self):
        self._handlers: Dict[str, MessageHandler] = {}

    def register(self, handler: MessageHandler) -> None:
        msg_type = handler.message_type()
        if msg_type in self._handlers:
            logger.warning(
                f"Overwriting existing handler for message type: {msg_type}"
            )
        self._handlers[msg_type] = handler
        logger.info(f"Registered handler for message type: {msg_type}")

    def get_handler(self, message_type: str) -> Optional[MessageHandler]:
        return self._handlers.get(message_type)

    def registered_types(self) -> List[str]:
        return list(self._handlers.keys())


class DeadLetterQueueManager:
    def __init__(self, sqs_client, dlq_url: str):
        self.sqs_client = sqs_client
        self.dlq_url = dlq_url

    def send_to_dlq(self, message: JobMessage, error: str) -> None:
        try:
            dlq_body = {
                'original_message_id': message.message_id,
                'type': message.message_type,
                'payload': message.payload,
                'error': str(error),
                'retry_count': message.retry_count,
                'failed_at': datetime.utcnow().isoformat(),
            }
            self.sqs_client.send_message(
                QueueUrl=self.dlq_url,
                MessageBody=json.dumps(dlq_body),
                MessageAttributes={
                    'OriginalMessageType': {
                        'DataType': 'String',
                        'StringValue': message.message_type,
                    },
                    'ErrorMessage': {
                        'DataType': 'String',
                        'StringValue': str(error)[:256],
                    }
                }
            )
            logger.info(
                f"Message {message.message_id} sent to DLQ"
            )
        except ClientError as e:
            logger.error(
                f"Failed to send message {message.message_id} to DLQ: {e}"
            )


class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 300,
        max_retries: int = 3,
        dlq_url: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        endpoint_url: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.max_retries = max_retries
        self._running = False
        self._processed_count = 0
        self._error_count = 0

        client_kwargs = {'region_name': region_name}
        if aws_access_key_id and aws_secret_access_key:
            client_kwargs['aws_access_key_id'] = aws_access_key_id
            client_kwargs['aws_secret_access_key'] = aws_secret_access_key
        if endpoint_url:
            client_kwargs['endpoint_url'] = endpoint_url

        self.sqs_client = boto3.client('sqs', **client_kwargs)
        self.registry = HandlerRegistry()

        self.dlq_manager = None
        if dlq_url:
            self.dlq_manager = DeadLetterQueueManager(self.sqs_client, dlq_url)

        self._register_default_handlers()

    def _register_default_handlers(self) -> None:
        self.registry.register(EmailNotificationHandler())
        self.registry.register(DataProcessingHandler())
        self.registry.register(ReportGenerationHandler())
        self.registry.register(WebhookHandler())

    def register_handler(self, handler: MessageHandler) -> None:
        self.registry.register(handler)

    def _poll_messages(self) -> List[Dict]:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                MessageAttributeNames=['All'],
                AttributeNames=['All'],
            )
            return response.get('Messages', [])
        except ClientError as e:
            logger.error(f"Error polling messages from SQS: {e}")
            return []

    def _delete_message(self, receipt_handle: str) -> None:
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
            )
        except ClientError as e:
            logger.error(f"Error deleting message: {e}")

    def _change_message_visibility(
        self, receipt_handle: str, timeout: int
    ) -> None:
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout,
            )
        except ClientError as e:
            logger.error(f"Error changing message visibility: {e}")

    def _requeue_message(self, message: JobMessage) -> None:
        try:
            new_retry_count = message.retry_count + 1
            body = {
                'type': message.message_type,
                'payload': message.payload,
                'attributes': message.attributes,
            }
            self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                MessageBody=json.dumps(body),
                DelaySeconds=min(new_retry_count * 30, 900),
                MessageAttributes={
                    'RetryCount': {
                        'DataType': 'Number',
                        'StringValue': str(new_retry_count),
                    }
                }
            )
            logger.info(
                f"Message {message.message_id} requeued "
                f"(retry {new_retry_count}/{self.max_retries})"
            )
        except ClientError as e:
            logger.error(f"Error requeuing message {message.message_id}: {e}")

    def _process_message(self, sqs_message: Dict) -> None:
        message = None
        try:
            message = JobMessage.from_sqs_message(sqs_message)
            logger.info(
                f"Processing message {message.message_id} "
                f"of type '{message.message_type}'"
            )

            handler = self.registry.get_handler(message.message_type)
            if handler is None:
                logger.warning(
                    f"No handler registered for message type: "
                    f"'{message.message_type}'. "
                    f"Registered types: {self.registry.registered_types()}"
                )
                if self.dlq_manager:
                    self.dlq_manager.send_to_dlq(
                        message,
                        f"No handler for type: {message.message_type}"
                    )
                self._delete_message(message.receipt_handle)
                self._error_count += 1
                return

            success = handler.handle(message)

            if success:
                self._delete_message(message.receipt_handle)
                self._processed_count += 1
                logger.info(
                    f"Successfully processed message {message.message_id}"
                )
            else:
                self._handle_failure(
                    message, "Handler returned False"
                )

        except json.JSONDecodeError as e:
            logger.error(
                f"Invalid JSON in message body: {e}"
            )
            receipt_handle = sqs_message.get('ReceiptHandle')
            if receipt_handle:
                self._delete_message(receipt_handle)
            self._error_count += 1

        except Exception as e:
            logger.exception(
                f"Unexpected error processing message: {e}"
            )
            if message:
                self._handle_failure(message, str(e))
            self._error_count += 1

    def _handle_failure(self, message: JobMessage, error: str) -> None:
        if message.retry_count >= self.max_retries:
            logger.error(
                f"Message {message.message_id} exceeded max retries "
                f"({self.max_retries}). Sending to DLQ."
            )
            if self.dlq_manager:
                self.dlq_manager.send_to_dlq(message, error)
            self._delete_message(message.receipt_handle)
        else:
            self._delete_message(message.receipt_handle)
            self._requeue_message(message)

        self._error_count += 1

    def _setup_signal_handlers(self) -> None:
        def signal_handler(signum, frame):
            sig_name = signal.Signals(signum).name
            logger.info(
                f"Received {sig_name}. Shutting down gracefully..."
            )
            self._running = False

        signal.signal(signal.SIGINT, signal_handler)
        signal.signal(signal.SIGTERM, signal_handler)

    def start(self) -> None:
        self._running = True
        self._setup_signal_handlers()

        logger.info(
            f"SQS Worker started. Polling queue: {self.queue_url}"
        )
        logger.info(
            f"Registered message types: {self.registry.registered_types()}"
        )

        while self._running:
            try:
                messages = self._poll_messages()

                if not messages:
                    logger.debug("No messages received. Continuing to poll...")
                    continue

                logger.info(f"Received {len(messages)} message(s)")

                for sqs_message in messages:
                    if not self._running:
                        break
                    self._process_message(sqs_message)

                logger.info(
                    f"Stats - Processed: {self._processed_count}, "
                    f"Errors: {self._error_count}"
                )

            except Exception as e:
                logger.exception(f"Error in main polling loop: {e}")
                if self._running:
                    time.sleep(5)

        logger.info(
            f"SQS Worker stopped. "
            f"Total processed: {self._processed_count}, "
            f"Total errors: {self._error_count}"
        )

    def stop(self) -> None:
        logger.info("Stop requested.")
        self._running = False

    @property
    def stats(self) -> Dict[str, int]:
        return {
            'processed': self._processed_count,
            'errors': self._error_count,
        }


def send_test_messages(queue_url: str, region_name: str = 'us-east-1',
                       endpoint_url: Optional[str] = None):
    """Utility function to send test messages to the queue."""
    client_kwargs = {'region_name': region_name}
    if endpoint_url:
        client_kwargs['endpoint_url'] = endpoint_url

    sqs = boto3.client('sqs', **client_kwargs)

    test_messages = [
        {
            'type': 'email_notification',
            'payload': {
                'recipient': 'user@example.com',
                'subject': 'Welcome!',
                'body': 'Welcome to our platform.',
            }
        },
        {
            'type': 'data_processing',
            'payload': {
                'source': 's3://my-bucket/data.csv',
                'operation': 'aggregate',
                'parameters': {'group_by': 'category', 'metric': 'sum'},
            }
        },
        {
            'type': 'report_generation',
            'payload': {
                'report_type': 'monthly_sales',
                'date_range': {'start': '2024-01-01', 'end': '2024-01-31'},
                'output_format': 'pdf',
            }
        },
        {
            'type': 'webhook',
            'payload': {
                'url': 'https://api.example.com/webhook',
                'method': 'POST',
                'data': {'event': 'order_completed', 'order_id': '12345'},
                'headers': {'Authorization': 'Bearer token123'},
            }
        },
    ]

    for msg in test_messages:
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps(msg),
        )
        logger.info(
            f"Sent test message: type={msg['type']}, "
            f"MessageId={response['MessageId']}"
        )


